1	/**
2	 * A live cell on the Game of Life grid, represented as [x, y] coordinates.
3	 * The grid is conceptually infinite; only live cells are tracked.
4	 */
5	export type Cell = [number, number];
6	
7	/**
8	 * Computes the next generation of live cells from the current generation
9	 * by applying Conway's Game of Life rules:
10	 * - A live cell with 2 or 3 live neighbors survives.
11	 * - A dead cell with exactly 3 live neighbors becomes alive (reproduction).
12	 * - All other cells are dead in the next generation (underpopulation
13	 *   when <2 live neighbors, overpopulation when >3).
14	 */
15	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
16	  [-1, -1], [0, -1], [1, -1],
17	  [-1,  0],          [1,  0],
18	  [-1,  1], [0,  1], [1,  1],
19	];
20	
21	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
22	
23	export function nextGeneration(currentGeneration: Cell[]): Cell[] {
24	  const liveKeys = new Set(currentGeneration.map(cellKey));
25	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
26	
27	  for (const [x, y] of currentGeneration) {
28	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
29	      const neighbor: Cell = [x + dx, y + dy];
30	      const k = cellKey(neighbor);
31	      const entry = neighborCounts.get(k);
32	      if (entry) entry.count++;
33	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
34	    }
35	  }
36	
37	  const isAliveNextGeneration = (key: string, liveNeighborCount: number): boolean =>
38	    liveNeighborCount === 3 || (liveNeighborCount === 2 && liveKeys.has(key));
39	
40	  const next: Cell[] = [];
41	  for (const [key, { cell, count }] of neighborCounts) {
42	    if (isAliveNextGeneration(key, count)) next.push(cell);
43	  }
44	  return next;
45	}
46

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent live cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 Survival: middle of a horizontal triple survives — (1,0) has 2 live neighbors", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("Rule 3 Overpopulation: center of 3x3 block dies — (1,1) has 8 live neighbors", () => {
19	    const fullBlock: [number, number][] = [
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ];
24	    const result = nextGeneration(fullBlock);
25	    expect(result).not.toContainEqual([1, 1]);
26	    expect(result).toContainEqual([0, 0]);
27	  });
28	  it("Rule 4 Reproduction: dead (1,1) with exactly 3 live neighbors becomes alive — [(0,0),(1,0),(0,1)] → contains (1,1)", () => {
29	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
30	    expect(result).toContainEqual([1, 1]);
31	  });
32	  it("Block still life is stable — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
33	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
34	    const result = nextGeneration(block);
35	    expect(result).toHaveLength(4);
36	    for (const cell of block) {
37	      expect(result).toContainEqual(cell);
38	    }
39	  });
40	  it.todo("Blinker oscillates: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
41	  it.todo("handles negative coordinates (blinker shifted into negatives)");
42	});
