export function nextGeneration(currentGeneration: Cell[]): Cell[] {
  const liveKeys = new Set(currentGeneration.map(cellKey));
  const neighborCounts = new Map<string, number>();
  const cellsByKey = new Map<string, Cell>();

  for (const [x, y] of currentGeneration) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = cellKey(neighbor);
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      cellsByKey.set(key, neighbor);
    }
  }

  const isAliveNextGeneration = (key: string, liveNeighborCount: number): boolean =>
    liveNeighborCount === 3 || (liveNeighborCount === 2 && liveKeys.has(key));

  const next: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    if (isAliveNextGeneration(key, count)) next.push(cellsByKey.get(key)!);
  }
  return next;
}
